From 3e6ab85019334a5b2a438264afdebe439cfc82b4 Mon Sep 17 00:00:00 2001
From: Chen Cohen <chenc@tikalk.com>
Date: Sat, 22 Jul 2017 18:55:55 +0300
Subject: [PATCH] JENKINS-36333 - Attach permission to Job.Build


diff --git a/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java b/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java
index f73b0ad..cf21543 100644
--- a/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java
+++ b/src/main/java/com/tikal/jenkins/plugins/multijob/MultiJobResumeBuild.java
@@ -1,11 +1,6 @@
 package com.tikal.jenkins.plugins.multijob;

-import hudson.model.Action;
-import hudson.model.Cause;
-import hudson.model.CauseAction;
-import hudson.model.ParametersAction;
-import hudson.model.Queue;
-import hudson.model.Run;
+import hudson.model.*;
 import jenkins.model.Jenkins;
 import jenkins.model.RunAction2;
 import org.kohsuke.stapler.StaplerProxy;
@@ -25,7 +20,7 @@ public class MultiJobResumeBuild implements RunAction2, StaplerProxy {
     }

     public String getIconFileName() {
-        return Jenkins.getInstance().hasPermission(Jenkins.ADMINISTER) ? "plugin/jenkins-multijob-plugin/tool32.png" : null;
+        return Jenkins.getInstance().hasPermission(Job.BUILD) ? "plugin/jenkins-multijob-plugin/tool32.png" : null;
 	}

     public String getDisplayName() {
@@ -75,7 +70,7 @@ public class MultiJobResumeBuild implements RunAction2, StaplerProxy {

     @Override
     public Object getTarget() {
-        Jenkins.getInstance().checkPermission(Jenkins.ADMINISTER);
+        Jenkins.getInstance().checkPermission(Job.BUILD);
         return this;
     }
 }
-- 
2.34.1

Based on the commit message, the root cause and the patch provided below, you need to:

1. explain how the bug occurs, including all code statements that are most likely to lead to the bug and why. 
2. explain how the bug is fixed, including code statements fixing the bug and why. 

You must include one or more code statements in point 1 and 2.
Code statements included in point 1 should be as brief as possible, only include the ones that are most related to the root cause and  the number of code statements may not exceed 3.


Here is the commit message:
JENKINS-36333 - Attach permission to Job.Build

Here is the root cause:
The bug was caused by the requirement of administrative permissions (`Jenkins.ADMINISTER`) to access certain functionalities related to job builds, which restricted users who only had build permissions from performing necessary actions. This led to usability issues for users who should have been able to resume builds but were blocked due to insufficient permissions.

Here is the patch:
 package com.tikal.jenkins.plugins.multijob;

-import hudson.model.Action;
-import hudson.model.Cause;
-import hudson.model.CauseAction;
-import hudson.model.ParametersAction;
-import hudson.model.Queue;
-import hudson.model.Run;
+import hudson.model.*;
 import jenkins.model.Jenkins;
 import jenkins.model.RunAction2;

     public String getIconFileName() {
-        return Jenkins.getInstance().hasPermission(Jenkins.ADMINISTER) ? "plugin/jenkins-multijob-plugin/tool32.png" : null;
+        return Jenkins.getInstance().hasPermission(Job.BUILD) ? "plugin/jenkins-multijob-plugin/tool32.png" : null;
 	}


     @Override
     public Object getTarget() {
-        Jenkins.getInstance().checkPermission(Jenkins.ADMINISTER);
+        Jenkins.getInstance().checkPermission(Job.BUILD);
         return this;
     }
 }


